content:
{
  "sentences": [
    {
      "text": "如果下雨的話，我們就不要去公園了。",
      "pinyin": "Rúguǒ xià yǔ de huà, wǒmen jiù bù yào qù gōngyuán le.",
      "pinyin_numeric": "ru2 guo3 xia4 yu3 de0 hua4, wo3 men0 jiu4 bu4 yao4 qu4 gong1 yuan2 le0.",
      "translation_en": "If it rains, we won't go to the park.",
      "translation_ko": "비가 오면, 우리는 공원에 가지 않을 거예요."
    },
    {
      "text": "要是你遲到的話，我們就來不及看電影了。",
      "pinyin": "Yàoshi nǐ chídào de huà, wǒmen jiù láibují kàn diànyǐng le.",
      "pinyin_numeric": "yao4 shi4 ni3 chi2 dao4 de0 hua4, wo3 men0 jiu4 lai2 bu4 ji2 kan4 dian4 ying3 le0.",
      "translation_en": "If you are late, we won't make it to the movie.",
      "translation_ko": "네가 늦으면, 우리는 영화를 보러 갈 시간이 없을 거예요."
    },
    {
      "text": "你最好帶傘，不然會淋濕。",
      "pinyin": "Nǐ zuì hǎo dài sǎn, bùrán huì lín shī.",
      "pinyin_numeric": "ni3 zui4 hao3 dai4 san3, bu4 ran2 hui4 lin2 shi1.",
      "translation_en": "You'd better bring an umbrella, otherwise you'll get wet.",
      "translation_ko": "우산을 가져가는 게 좋아요, 그렇지 않으면 비에 젖을 거예요."
    },
    {
      "text": "假如明天沒空的話，我們就改天再約。",
      "pinyin": "Jiǎrú míngtiān méi kòng de huà, wǒmen jiù gǎitiān zài yuē.",
      "pinyin_numeric": "jia3 ru2 ming2 tian1 mei2 kong4 de0 hua4, wo3 men0 jiu4 gai3 tian1 zai4 yue1.",
      "translation_en": "If you're not free tomorrow, we'll schedule another day.",
      "translation_ko": "만약 내일 시간이 안 되면, 다른 날 다시 약속해요."
    },
    {
      "text": "你必須帶備用鑰匙，否則的話會進不了家。",
      "pinyin": "Nǐ bìxū dài bèiyòng yàoshi, fǒuzé de huà huì jìn bù liǎo jiā.",
      "pinyin_numeric": "ni3 bi4 xu1 dai4 bei4 yong4 yao4 shi0, fou3 ze2 de0 hua4 hui4 jin4 bu4 liao3 jia1.",
      "translation_en": "You must bring a spare key, otherwise you won't be able to get into the house.",
      "translation_ko": "여분 열쇠를 꼭 가져가야 해요, 그렇지 않으면 집에 들어갈 수 없어요."
    },
    {
      "text": "要是颱風來了的話，我們就待在家裡。",
      "pinyin": "Yàoshi táifēng lái le de huà, wǒmen jiù dāi zài jiā lǐ.",
      "pinyin_numeric": "yao4 shi4 tai2 feng1 lai2 le0 de0 hua4, wo3 men0 jiu4 dai1 zai4 jia1 li3.",
      "translation_en": "If a typhoon comes, we'll stay at home.",
      "translation_ko": "태풍이 오면, 우리는 집에 있을 거예요."
    },
    {
      "text": "你最好早點出門，不然會塞車。",
      "pinyin": "Nǐ zuì hǎo zǎo diǎn chūmén, bùrán huì sāichē.",
      "pinyin_numeric": "ni3 zui4 hao3 zao3 dian3 chu1 men2, bu4 ran2 hui4 sai1 che1.",
      "translation_en": "You'd better leave early, otherwise you'll get stuck in traffic.",
      "translation_ko": "일찍 나가는 게 좋아요, 그렇지 않으면 차가 막힐 거예요."
    },
    {
      "text": "如果手機沒電的話，我就用備用方案。",
      "pinyin": "Rúguǒ shǒujī méi diàn de huà, wǒ jiù yòng bèiyòng fāng'àn.",
      "pinyin_numeric": "ru2 guo3 shou3 ji1 mei2 dian4 de0 hua4, wo3 jiu4 yong4 bei4 yong4 fang1 an4.",
      "translation_en": "If my phone runs out of battery, I'll use the backup plan.",
      "translation_ko": "핸드폰 배터리가 없으면, 저는 예비 계획을 사용할 거예요."
    },
    {
      "text": "萬一找不到餐廳的話，我們就吃便利商店。",
      "pinyin": "Wànyī zhǎo bù dào cāntīng de huà, wǒmen jiù chī biànlì shāngdiàn.",
      "pinyin_numeric": "wan4 yi1 zhao3 bu4 dao4 can1 ting1 de0 hua4, wo3 men0 jiu4 chi1 bian4 li4 shang1 dian4.",
      "translation_en": "In case we can't find a restaurant, we'll eat at the convenience store.",
      "translation_ko": "만약 식당을 찾지 못하면, 우리는 편의점에서 먹을 거예요."
    },
    {
      "text": "你千萬別忘記帶悠遊卡，否則的話會很麻煩。",
      "pinyin": "Nǐ qiānwàn bié wàngjì dài yōuyóukǎ, fǒuzé de huà huì hěn máfan.",
      "pinyin_numeric": "ni3 qian1 wan4 bie2 wang4 ji4 dai4 you1 you2 ka3, fou3 ze2 de0 hua4 hui4 hen3 ma2 fan0.",
      "translation_en": "Don't forget to bring your EasyCard, otherwise it'll be very troublesome.",
      "translation_ko": "유유카드를 꼭 잊지 말고 가져가세요, 그렇지 않으면 매우 번거로울 거예요."
    }
  ]
}
